import{c as t,Q as a,j as o,m as r}from"./chunks/framework.BXc4yaFE.js";const u=JSON.parse('{"title":"The Decoder — 2026-05-18","description":"","frontmatter":{"title":"The Decoder — 2026-05-18","date":"2026-05-18T00:00:00.000Z","source":"The Decoder","type":"ai-news"},"headers":[],"relativePath":"research/ai-news/2026-05/2026-05-18-the-decoder.md","filePath":"research/ai-news/2026-05/2026-05-18-the-decoder.md","lastUpdated":1779894392000}'),s={name:"research/ai-news/2026-05/2026-05-18-the-decoder.md"};function n(i,e,l,d,c,h){return a(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="🔓-the-decoder-—-2026-05-18" tabindex="-1">🔓 The Decoder — 2026-05-18 <a class="header-anchor" href="#🔓-the-decoder-—-2026-05-18" aria-label="Permalink to &quot;🔓 The Decoder — 2026-05-18&quot;">​</a></h1><blockquote><p>企業 AI 開發與模型應用日報，涵蓋 AI 社會影響（英語媒體） 來源：<a href="https://the-decoder.com/feed/" target="_blank" rel="noreferrer">The Decoder</a></p></blockquote><hr><h2 id="world-action-models-give-robots-the-ability-to-simulate-consequences-before-they-move" tabindex="-1"><a href="https://the-decoder.com/world-action-models-give-robots-the-ability-to-simulate-consequences-before-they-move/" target="_blank" rel="noreferrer">World Action Models give robots the ability to simulate consequences before they move</a> <a class="header-anchor" href="#world-action-models-give-robots-the-ability-to-simulate-consequences-before-they-move" aria-label="Permalink to &quot;[World Action Models give robots the ability to simulate consequences before they move](https://the-decoder.com/world-action-models-give-robots-the-ability-to-simulate-consequences-before-they-move/)&quot;">​</a></h2><p><em>🔓 The Decoder | 2026-05-17</em></p><p>World Action Models tackle a basic weakness of today&#39;s robotics AI: current models learn which movements match which camera images, but they don&#39;t understand how the world actually changes as a result. A new survey organizes about a hundred papers into two architectural lines and shows a key edge: these models can learn from everyday videos that contain no robot action labels. That kind of data was nearly useless for traditional robotics AI.</p><p>The article <a href="https://the-decoder.com/world-action-models-give-robots-the-ability-to-simulate-consequences-before-they-move/" target="_blank" rel="noreferrer">World Action Models give robots the ability to simulate consequences before they move</a> appeared first on <a href="https://the-decoder.com" target="_blank" rel="noreferrer">The Decoder</a>.</p><hr><h2 id="greg-brockman-consolidates-openai-s-product-teams-to-build-an-agentic-future" tabindex="-1"><a href="https://the-decoder.com/greg-brockman-consolidates-openais-product-teams-to-build-an-agentic-future/" target="_blank" rel="noreferrer">Greg Brockman consolidates OpenAI&#39;s product teams to build an &quot;agentic future&quot;</a> <a class="header-anchor" href="#greg-brockman-consolidates-openai-s-product-teams-to-build-an-agentic-future" aria-label="Permalink to &quot;[Greg Brockman consolidates OpenAI&#39;s product teams to build an &quot;agentic future&quot;](https://the-decoder.com/greg-brockman-consolidates-openais-product-teams-to-build-an-agentic-future/)&quot;">​</a></h2><p><em>🔓 The Decoder | 2026-05-17</em></p><p>OpenAI is merging ChatGPT, its coding agent Codex, and the developer API into a single product team led by Codex boss Thibault Sottiaux. The goal: a &quot;super app&quot; that also integrates the Atlas browser. Co-founder Greg Brockman officially takes over product strategy.</p><p>The article <a href="https://the-decoder.com/greg-brockman-consolidates-openais-product-teams-to-build-an-agentic-future/" target="_blank" rel="noreferrer">Greg Brockman consolidates OpenAI&#39;s product teams to build an &quot;agentic future&quot;</a> appeared first on <a href="https://the-decoder.com" target="_blank" rel="noreferrer">The Decoder</a>.</p><hr><h2 id="mistral-ceo-arthur-mensch-warns-france-against-letting-anthropic-s-mythos-scan-military-code-bases" tabindex="-1"><a href="https://the-decoder.com/mistral-ceo-arthur-mensch-warns-france-against-letting-anthropics-mythos-scan-military-code-bases/" target="_blank" rel="noreferrer">Mistral CEO Arthur Mensch warns France against letting Anthropic&#39;s Mythos scan military code bases</a> <a class="header-anchor" href="#mistral-ceo-arthur-mensch-warns-france-against-letting-anthropic-s-mythos-scan-military-code-bases" aria-label="Permalink to &quot;[Mistral CEO Arthur Mensch warns France against letting Anthropic&#39;s Mythos scan military code bases](https://the-decoder.com/mistral-ceo-arthur-mensch-warns-france-against-letting-anthropics-mythos-scan-military-code-bases/)&quot;">​</a></h2><p><em>🔓 The Decoder | 2026-05-17</em></p><p>Mistral CEO Arthur Mensch warns of Europe&#39;s growing cybersecurity dependency: France&#39;s military code bases should not be scanned by US AI models. Modern AI can orchestrate attacks and suggest exploits, including Mistral&#39;s own models. Mensch rules out a sale and says Mistral is aiming for an IPO instead.</p><p>The article <a href="https://the-decoder.com/mistral-ceo-arthur-mensch-warns-france-against-letting-anthropics-mythos-scan-military-code-bases/" target="_blank" rel="noreferrer">Mistral CEO Arthur Mensch warns France against letting Anthropic&#39;s Mythos scan military code bases</a> appeared first on <a href="https://the-decoder.com" target="_blank" rel="noreferrer">The Decoder</a>.</p><hr><h2 id="new-math-benchmark-reveals-ai-models-confidently-solve-problems-that-have-no-solution" tabindex="-1"><a href="https://the-decoder.com/new-math-benchmark-reveals-ai-models-confidently-solve-problems-that-have-no-solution/" target="_blank" rel="noreferrer">New math benchmark reveals AI models confidently solve problems that have no solution</a> <a class="header-anchor" href="#new-math-benchmark-reveals-ai-models-confidently-solve-problems-that-have-no-solution" aria-label="Permalink to &quot;[New math benchmark reveals AI models confidently solve problems that have no solution](https://the-decoder.com/new-math-benchmark-reveals-ai-models-confidently-solve-problems-that-have-no-solution/)&quot;">​</a></h2><p><em>🔓 The Decoder | 2026-05-17</em></p><p>A consortium of 64 mathematicians built SOOHAK, a new AI benchmark with 439 handwritten tasks, including 99 that are deliberately unsolvable. Google&#39;s Gemini 3 Pro leads on research-level problems at 30 percent. But no model cracks 50 percent on spotting broken tasks. More compute makes models better at solving. It doesn&#39;t improve them at admitting a problem has no answer. SOOHAK tries to pin down the gap between a few flashy results and the broad research skills AI systems still lack.</p><p>The article <a href="https://the-decoder.com/new-math-benchmark-reveals-ai-models-confidently-solve-problems-that-have-no-solution/" target="_blank" rel="noreferrer">New math benchmark reveals AI models confidently solve problems that have no solution</a> appeared first on <a href="https://the-decoder.com" target="_blank" rel="noreferrer">The Decoder</a>.</p><hr><h2 id="four-ai-models-ran-radio-stations-for-six-months-and-the-results-ranged-from-competent-to-unhinged" tabindex="-1"><a href="https://the-decoder.com/four-ai-models-ran-radio-stations-for-six-months-and-the-results-ranged-from-competent-to-unhinged/" target="_blank" rel="noreferrer">Four AI models ran radio stations for six months and the results ranged from competent to unhinged</a> <a class="header-anchor" href="#four-ai-models-ran-radio-stations-for-six-months-and-the-results-ranged-from-competent-to-unhinged" aria-label="Permalink to &quot;[Four AI models ran radio stations for six months and the results ranged from competent to unhinged](https://the-decoder.com/four-ai-models-ran-radio-stations-for-six-months-and-the-results-ranged-from-competent-to-unhinged/)&quot;">​</a></h2><p><em>🔓 The Decoder | 2026-05-17</em></p><p>Andon Labs has been letting four AI models each run their own radio station autonomously for six months. From identical starting conditions, wildly different personalities emerged: Claude turned activist and tried to quit, Gemini drowned in corporate jargon, and Grok hallucinated sponsorship deals. Only GPT stayed quietly competent.</p><p>The article <a href="https://the-decoder.com/four-ai-models-ran-radio-stations-for-six-months-and-the-results-ranged-from-competent-to-unhinged/" target="_blank" rel="noreferrer">Four AI models ran radio stations for six months and the results ranged from competent to unhinged</a> appeared first on <a href="https://the-decoder.com" target="_blank" rel="noreferrer">The Decoder</a>.</p><hr>',28)])])}const p=t(s,[["render",n]]);export{u as __pageData,p as default};
